from typing import Optional, List, Dict, Any
import psycopg2
from psycopg2.extras import RealDictCursor
from app.models.user import User, UserFilter


class UserRepository:
    def __init__(self, connection):
        self.conn = connection

    def find_by_id(self, user_id: str) -> Optional[Dict[str, Any]]:
        with self.conn.cursor(cursor_factory=RealDictCursor) as cur:
            cur.execute(
                "SELECT id, name, email, role, created_at FROM users WHERE id = %s",
                (user_id,)
            )
            return cur.fetchone()

    def search(self, filters: UserFilter) -> List[Dict[str, Any]]:
        conditions = []
        params = []

        if filters.name:
            conditions.append("name ILIKE %s")
            params.append(f"%{filters.name}%")

        if filters.role:
            conditions.append("role = %s")
            params.append(filters.role)

        if filters.created_after:
            conditions.append("created_at >= %s")
            params.append(filters.created_after)

        where_clause = "WHERE " + " AND ".join(conditions) if conditions else ""
        query = f"SELECT id, name, email, role, created_at FROM users {where_clause} ORDER BY created_at DESC LIMIT 100"

        with self.conn.cursor(cursor_factory=RealDictCursor) as cur:
            cur.execute(query, params)
            return cur.fetchall()
